const express = require('express');
const app = express();
const morgan = require('morgan')
app.use(morgan('dev'))
const port = 3000;
console.log('Server started on port '+port);
app.get('/', function (req, res) {
    console.log(req.headers['x-forwarded-for']+ ' - - '+ req.method +' '+ req.url +' '+ req.httpVersion + ' '+ req.ip);
  res.send('Hello World!');
});
app.listen(port);

